//! P2 reconstruction — proposal silhouette -> coarse watertight mesh + geometric descriptor.
//!
//! For a video proposal we don't have a clean single-object profile (the MAPS/sweep priors the
//! Wholly uploader uses assume that). The honest, robust per-frame mesh is an **extruded
//! silhouette slab**: every foreground pixel becomes a front+back quad, and every pixel edge
//! that borders background becomes a side wall. This is watertight by construction and naturally
//! represents genus — holes in the silhouette become tunnels through the slab — so the genus
//! router just records topology rather than needing separate handle synthesis.
//!
//! The mask is downsampled to a bounded resolution first, so triangle counts stay sane.

use crate::vision::Proposal;
use std::collections::HashMap;
use std::fmt::Write as _;

/// Cap the meshing resolution (longest silhouette side, in cells).
const MAX_MESH_DIM: usize = 64;

#[derive(Clone, Default)]
pub struct Mesh {
    pub verts: Vec<[f32; 3]>,
    pub faces: Vec<[u32; 3]>,
}

impl Mesh {
    pub fn vertex_count(&self) -> usize {
        self.verts.len()
    }
    pub fn face_count(&self) -> usize {
        self.faces.len()
    }

    /// ASCII PLY (small meshes; easy to inspect/render).
    pub fn to_ply(&self) -> String {
        let mut s = String::new();
        let _ = write!(
            s,
            "ply\nformat ascii 1.0\nelement vertex {}\nproperty float x\nproperty float y\nproperty float z\nelement face {}\nproperty list uchar int vertex_indices\nend_header\n",
            self.verts.len(),
            self.faces.len()
        );
        for v in &self.verts {
            let _ = writeln!(s, "{} {} {}", v[0], v[1], v[2]);
        }
        for f in &self.faces {
            let _ = writeln!(s, "3 {} {} {}", f[0], f[1], f[2]);
        }
        s
    }
}

/// A 2.5D geometric descriptor of a proposal silhouette (resolution-independent).
#[derive(Clone, Debug)]
pub struct ObjectDescriptor {
    pub genus: u32,
    /// Fraction of the bbox filled by the silhouette (solidity).
    pub fill: f32,
    /// Aspect ratio (bbox width / height).
    pub aspect: f32,
    /// Elongation from silhouette moments: sqrt(λ_major/λ_minor), >= 1.
    pub elongation: f32,
    /// Orientation of the major axis, radians, [-π/2, π/2].
    pub orientation: f32,
}

/// Downsample a binary mask to at most `MAX_MESH_DIM` on its longer side (majority vote).
fn downsample_mask(mask: &[u8], mw: usize, mh: usize) -> (Vec<u8>, usize, usize) {
    let long = mw.max(mh);
    if long <= MAX_MESH_DIM {
        return (mask.to_vec(), mw, mh);
    }
    let nw = (mw * MAX_MESH_DIM / long).max(1);
    let nh = (mh * MAX_MESH_DIM / long).max(1);
    let mut out = vec![0u8; nw * nh];
    for ny in 0..nh {
        let y0 = ny * mh / nh;
        let y1 = ((ny + 1) * mh / nh).max(y0 + 1).min(mh);
        for nx in 0..nw {
            let x0 = nx * mw / nw;
            let x1 = ((nx + 1) * mw / nw).max(x0 + 1).min(mw);
            let mut on = 0usize;
            let mut tot = 0usize;
            for yy in y0..y1 {
                for xx in x0..x1 {
                    tot += 1;
                    if mask[yy * mw + xx] != 0 {
                        on += 1;
                    }
                }
            }
            out[ny * nw + nx] = if on * 2 >= tot { 1 } else { 0 };
        }
    }
    (out, nw, nh)
}

/// Compute the silhouette descriptor (moments-based, on the full-res mask).
pub fn describe(p: &Proposal) -> ObjectDescriptor {
    let mw = p.mw as usize;
    let mh = p.mh as usize;
    let mut n = 0f64;
    let (mut sx, mut sy) = (0f64, 0f64);
    for y in 0..mh {
        for x in 0..mw {
            if p.mask[y * mw + x] != 0 {
                n += 1.0;
                sx += x as f64;
                sy += y as f64;
            }
        }
    }
    let fill = if mw * mh > 0 {
        (n as f32) / ((mw * mh) as f32)
    } else {
        0.0
    };
    let aspect = if mh > 0 { mw as f32 / mh as f32 } else { 1.0 };
    if n < 2.0 {
        return ObjectDescriptor {
            genus: p.genus,
            fill,
            aspect,
            elongation: 1.0,
            orientation: 0.0,
        };
    }
    let mx = sx / n;
    let my = sy / n;
    let (mut cxx, mut cyy, mut cxy) = (0f64, 0f64, 0f64);
    for y in 0..mh {
        for x in 0..mw {
            if p.mask[y * mw + x] != 0 {
                let dx = x as f64 - mx;
                let dy = y as f64 - my;
                cxx += dx * dx;
                cyy += dy * dy;
                cxy += dx * dy;
            }
        }
    }
    cxx /= n;
    cyy /= n;
    cxy /= n;
    // Eigenvalues of the 2x2 covariance.
    let tr = cxx + cyy;
    let det = cxx * cyy - cxy * cxy;
    let disc = (tr * tr / 4.0 - det).max(0.0).sqrt();
    let l1 = tr / 2.0 + disc;
    let l2 = (tr / 2.0 - disc).max(1e-9);
    let elongation = (l1 / l2).sqrt() as f32;
    let orientation = 0.5 * (2.0 * cxy).atan2(cxx - cyy);
    ObjectDescriptor {
        genus: p.genus,
        fill,
        aspect,
        elongation,
        orientation: orientation as f32,
    }
}

/// Extrude a proposal's silhouette into a watertight slab mesh. `depth` is the slab thickness
/// in normalised object units (x spans `aspect`, y spans 1.0). Genus is preserved as tunnels.
pub fn extrude(p: &Proposal, depth: f32) -> Mesh {
    let (mask, mw, mh) = downsample_mask(&p.mask, p.mw as usize, p.mh as usize);
    let mut mesh = Mesh::default();
    if mw == 0 || mh == 0 {
        return mesh;
    }
    let at = |x: i32, y: i32| -> bool {
        x >= 0 && y >= 0 && (x as usize) < mw && (y as usize) < mh && mask[y as usize * mw + x as usize] != 0
    };

    // Normalised cell geometry: object spans [-aspect/2, aspect/2] x [0.5, -0.5] (y flipped), z in ±d/2.
    let aspect = mw as f32 / mh as f32;
    let cw = aspect / mw as f32;
    let ch = 1.0 / mh as f32;
    let zf = depth * 0.5;
    let zb = -depth * 0.5;
    let px = |xi: usize| -> f32 { -aspect * 0.5 + xi as f32 * cw };
    let py = |yi: usize| -> f32 { 0.5 - yi as f32 * ch };

    // Dedup grid corners: key (xi, yi, side) where side 0=back(zb) 1=front(zf).
    let mut idx: HashMap<(usize, usize, u8), u32> = HashMap::new();
    let mut vert = |xi: usize, yi: usize, side: u8, mesh: &mut Mesh| -> u32 {
        *idx.entry((xi, yi, side)).or_insert_with(|| {
            let z = if side == 1 { zf } else { zb };
            mesh.verts.push([px(xi), py(yi), z]);
            (mesh.verts.len() - 1) as u32
        })
    };

    for y in 0..mh {
        for x in 0..mw {
            if mask[y * mw + x] == 0 {
                continue;
            }
            // Corner grid indices for this cell.
            let (x0, x1, y0, y1) = (x, x + 1, y, y + 1);
            // Front cap (z=zf), CCW seen from +z.
            let f00 = vert(x0, y0, 1, &mut mesh);
            let f10 = vert(x1, y0, 1, &mut mesh);
            let f11 = vert(x1, y1, 1, &mut mesh);
            let f01 = vert(x0, y1, 1, &mut mesh);
            mesh.faces.push([f00, f11, f10]);
            mesh.faces.push([f00, f01, f11]);
            // Back cap (z=zb), reversed winding.
            let b00 = vert(x0, y0, 0, &mut mesh);
            let b10 = vert(x1, y0, 0, &mut mesh);
            let b11 = vert(x1, y1, 0, &mut mesh);
            let b01 = vert(x0, y1, 0, &mut mesh);
            mesh.faces.push([b00, b10, b11]);
            mesh.faces.push([b00, b11, b01]);
            // Side walls where a 4-neighbour is background/border.
            // Each wall quad connects the shared edge's front+back corners.
            // left edge (x0): neighbour (x-1,y)
            if !at(x as i32 - 1, y as i32) {
                let a = vert(x0, y0, 1, &mut mesh);
                let b = vert(x0, y1, 1, &mut mesh);
                let c = vert(x0, y1, 0, &mut mesh);
                let d = vert(x0, y0, 0, &mut mesh);
                mesh.faces.push([a, b, c]);
                mesh.faces.push([a, c, d]);
            }
            // right edge (x1): neighbour (x+1,y)
            if !at(x as i32 + 1, y as i32) {
                let a = vert(x1, y0, 1, &mut mesh);
                let b = vert(x1, y1, 1, &mut mesh);
                let c = vert(x1, y1, 0, &mut mesh);
                let d = vert(x1, y0, 0, &mut mesh);
                mesh.faces.push([a, c, b]);
                mesh.faces.push([a, d, c]);
            }
            // top edge (y0): neighbour (x,y-1)
            if !at(x as i32, y as i32 - 1) {
                let a = vert(x0, y0, 1, &mut mesh);
                let b = vert(x1, y0, 1, &mut mesh);
                let c = vert(x1, y0, 0, &mut mesh);
                let d = vert(x0, y0, 0, &mut mesh);
                mesh.faces.push([a, c, b]);
                mesh.faces.push([a, d, c]);
            }
            // bottom edge (y1): neighbour (x,y+1)
            if !at(x as i32, y as i32 + 1) {
                let a = vert(x0, y1, 1, &mut mesh);
                let b = vert(x1, y1, 1, &mut mesh);
                let c = vert(x1, y1, 0, &mut mesh);
                let d = vert(x0, y1, 0, &mut mesh);
                mesh.faces.push([a, b, c]);
                mesh.faces.push([a, c, d]);
            }
        }
    }
    mesh
}

/// Reconstruct a proposal: descriptor + extruded mesh. Depth scales with the shorter bbox side
/// (a plausible thickness; flat proposals stay thin, blobby ones get rounder).
pub fn reconstruct(p: &Proposal) -> (ObjectDescriptor, Mesh) {
    let d = describe(p);
    let depth = (0.6 / d.aspect.max(0.25)).clamp(0.15, 0.9);
    let mesh = extrude(p, depth);
    (d, mesh)
}
